- (void)scheduleVirtualDisplayActivationRetryForID:(NSString *)virtualDisplayID wantsMirror:(BOOL)wantsMirror
{
  if (virtualDisplayID.length == 0) {
    return;
  }

  if (![NSThread isMainThread]) {
    dispatch_async(dispatch_get_main_queue(), ^{
      [self scheduleVirtualDisplayActivationRetryForID:virtualDisplayID wantsMirror:wantsMirror];
    });
    return;
  }

  if (self.virtualDisplayActivationAttempts[virtualDisplayID] != nil) {
    return;
  }

  self.virtualDisplayActivationAttempts[virtualDisplayID] = @0;
  [self retryVirtualDisplayActivationForID:virtualDisplayID wantsMirror:wantsMirror attempt:1];
}


- (void)retryVirtualDisplayActivationForID:(NSString *)virtualDisplayID
                               wantsMirror:(BOOL)wantsMirror
                                   attempt:(NSUInteger)attempt
{
  if (virtualDisplayID.length == 0) {
    return;
  }

  if (![NSThread isMainThread]) {
    dispatch_async(dispatch_get_main_queue(), ^{
      [self retryVirtualDisplayActivationForID:virtualDisplayID wantsMirror:wantsMirror attempt:attempt];
    });
    return;
  }

  const NSUInteger maxAttempts = 12;
  NSDictionary *record = self.virtualDisplayRecords[virtualDisplayID];
  id virtualDisplay = self.virtualDisplays[virtualDisplayID];

  if (![record isKindOfClass:NSDictionary.class] || virtualDisplay == nil) {
    [self.virtualDisplayActivationAttempts removeObjectForKey:virtualDisplayID];
    return;
  }

  NSString *displayID = [self visibleDisplayIDForVirtualDisplay:virtualDisplay];
  BOOL shouldMirror = wantsMirror || [record[@"mirrorMode"] isEqualToString:@"target-mirrors-virtual"];

  if (displayID.length > 0) {
    NSMutableDictionary *updatedRecord = [record mutableCopy];
    updatedRecord[@"displayID"] = displayID;
    updatedRecord[@"status"] = @"Created";
    updatedRecord[@"lastError"] = @"";

    if (shouldMirror) {
      NSString *mirrorError = nil;
      updatedRecord = [[self recordByApplyingVirtualMirrorForID:virtualDisplayID
                                                         record:updatedRecord
                                                   errorMessage:&mirrorError] mutableCopy];
    }

    self.virtualDisplayRecords[virtualDisplayID] = updatedRecord;
    [self.virtualDisplayActivationAttempts removeObjectForKey:virtualDisplayID];
    [self persistVirtualDisplayRecords];
    NSLog(@"[macDisplayBar] Virtual display activation completed: id=%@ displayID=%@ mirrored=%@ attempt=%lu",
          virtualDisplayID,
          displayID,
          [updatedRecord[@"mirrorStatus"] isEqualToString:@"Mirrored to target"] ? @"YES" : @"NO",
          (unsigned long)attempt);
    return;
  }

  if (attempt >= maxAttempts) {
    NSMutableDictionary *failedRecord = [record mutableCopy];
    failedRecord[@"status"] = @"Create failed";
    failedRecord[@"lastError"] = @"Virtual display did not appear in active display list";
    failedRecord[@"mirrorMode"] = @"none";
    failedRecord[@"mirrorStatus"] = @"Not mirrored";
    [self.virtualDisplayActivationAttempts removeObjectForKey:virtualDisplayID];
    [self.virtualDisplays removeObjectForKey:virtualDisplayID];
    self.virtualDisplayRecords[virtualDisplayID] = failedRecord;
    [self persistVirtualDisplayRecords];
    NSLog(@"[macDisplayBar] Virtual display activation failed: id=%@ attempts=%lu",
          virtualDisplayID,
          (unsigned long)attempt);
    return;
  }

  NSMutableDictionary *pendingRecord = [record mutableCopy];
  pendingRecord[@"status"] = @"Creating";
  pendingRecord[@"lastError"] = @"";
  if (shouldMirror) {
    pendingRecord[@"mirrorMode"] = @"target-mirrors-virtual";
    pendingRecord[@"mirrorStatus"] = @"Mirror pending";
  }
  self.virtualDisplayRecords[virtualDisplayID] = pendingRecord;
  self.virtualDisplayActivationAttempts[virtualDisplayID] = @(attempt);
  [self persistVirtualDisplayRecords];

  dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.25 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
    [self retryVirtualDisplayActivationForID:virtualDisplayID wantsMirror:wantsMirror attempt:attempt + 1];
  });
}

- (NSDictionary *)createVirtualDisplayRecordWithID:(NSString *)virtualDisplayID
                                   targetDisplayID:(NSString *)targetDisplayID
                                      serialNumber:(NSNumber *)serialNumber
                                             width:(double)width
                                            height:(double)height
                                       refreshRate:(double)refreshRate
                                           isHiDpi:(BOOL)isHiDpi
                                      errorMessage:(NSString **)errorMessage
{
  Class descriptorClass = NSClassFromString(@"CGVirtualDisplayDescriptor");
  Class displayClass = NSClassFromString(@"CGVirtualDisplay");
  Class modeClass = NSClassFromString(@"CGVirtualDisplayMode");
  Class settingsClass = NSClassFromString(@"CGVirtualDisplaySettings");

  if (descriptorClass == Nil || displayClass == Nil || modeClass == Nil || settingsClass == Nil) {
    if (errorMessage != nil) {
      *errorMessage = @"CGVirtualDisplay API unavailable";
    }

    NSLog(@"[macDisplayBar] Virtual display unavailable: missing CGVirtualDisplay runtime classes");
    return @{};
  }

  NSUInteger logicalWidth = MAX((NSUInteger)llround(width), 1);
  NSUInteger logicalHeight = MAX((NSUInteger)llround(height), 1);
  double normalizedRefreshRate = refreshRate > 0 ? refreshRate : 60;
  NSUInteger backingScale = isHiDpi ? 2 : 1;
  NSUInteger backingWidth = logicalWidth * backingScale;
  NSUInteger backingHeight = logicalHeight * backingScale;
  NSString *name = [NSString stringWithFormat:@"macDisplayBar Virtual %lux%lu",
                                              (unsigned long)logicalWidth,
                                              (unsigned long)logicalHeight];
  SEL modeInitSelector = RCTDisplayPrivateSelector(@"initWithWidth:height:refreshRate:");
  SEL displayInitSelector = RCTDisplayPrivateSelector(@"initWithDescriptor:");

  if (![modeClass instancesRespondToSelector:modeInitSelector] ||
      ![displayClass instancesRespondToSelector:displayInitSelector]) {
    if (errorMessage != nil) {
      *errorMessage = @"CGVirtualDisplay API shape unsupported";
    }

    NSLog(@"[macDisplayBar] Virtual display unavailable: unsupported CGVirtualDisplay selector shape");
    return @{};
  }

  id descriptor = RCTObjCAllocInit(descriptorClass);
  id settings = RCTObjCAllocInit(settingsClass);
  id modeAllocation = ((id (*)(Class, SEL))objc_msgSend)(modeClass, @selector(alloc));
  id mode = ((id (*)(id, SEL, unsigned int, unsigned int, double))objc_msgSend)(
      modeAllocation,
      modeInitSelector,
      (unsigned int)logicalWidth,
      (unsigned int)logicalHeight,
      normalizedRefreshRate);

  if (descriptor == nil || settings == nil || mode == nil) {
    if (errorMessage != nil) {
      *errorMessage = @"Virtual display object allocation failed";
    }

    NSLog(@"[macDisplayBar] Virtual display allocation failed: width=%lu height=%lu refreshRate=%.3f HiDPI=%@",
          (unsigned long)logicalWidth,
          (unsigned long)logicalHeight,
          normalizedRefreshRate,
          isHiDpi ? @"YES" : @"NO");
    return @{};
  }

  RCTObjCSetUnsignedInt(descriptor, RCTDisplayPrivateSelector(@"setVendorID:"), RCTVirtualDisplayVendorID);
  RCTObjCSetUnsignedInt(descriptor, RCTDisplayPrivateSelector(@"setProductID:"), RCTVirtualDisplayProductID);
  RCTObjCSetUnsignedInt(descriptor, RCTDisplayPrivateSelector(@"setSerialNum:"), serialNumber.unsignedIntValue);
  RCTObjCSetObject(descriptor, @selector(setName:), name);
  RCTObjCSetUnsignedInt(descriptor, RCTDisplayPrivateSelector(@"setMaxPixelsWide:"), (unsigned int)backingWidth);
  RCTObjCSetUnsignedInt(descriptor, RCTDisplayPrivateSelector(@"setMaxPixelsHigh:"), (unsigned int)backingHeight);
  RCTObjCSetCGSize(descriptor,
                   RCTDisplayPrivateSelector(@"setSizeInMillimeters:"),
                   CGSizeMake(25.4 * backingWidth / RCTVirtualDisplayPixelsPerInch,
                              25.4 * backingHeight / RCTVirtualDisplayPixelsPerInch));
  RCTObjCSetCGPoint(descriptor, RCTDisplayPrivateSelector(@"setWhitePoint:"), CGPointMake(0.3125, 0.3291));
  RCTObjCSetCGPoint(descriptor, RCTDisplayPrivateSelector(@"setRedPrimary:"), CGPointMake(0.6797, 0.3203));
  RCTObjCSetCGPoint(descriptor, RCTDisplayPrivateSelector(@"setGreenPrimary:"), CGPointMake(0.2559, 0.6983));
  RCTObjCSetCGPoint(descriptor, RCTDisplayPrivateSelector(@"setBluePrimary:"), CGPointMake(0.1494, 0.0557));

  SEL setDispatchQueueSelector = RCTDisplayPrivateSelector(@"setDispatchQueue:");
  if ([descriptor respondsToSelector:setDispatchQueueSelector]) {
    RCTObjCSetObject(descriptor, setDispatchQueueSelector, dispatch_get_main_queue());
  } else {
    RCTObjCSetObject(descriptor, RCTDisplayPrivateSelector(@"setQueue:"), dispatch_get_main_queue());
  }
  SEL terminationHandlerSelector = RCTDisplayPrivateSelector(@"setTerminationHandler:");
  if ([descriptor respondsToSelector:terminationHandlerSelector]) {
    __weak RCTDisplayCore *weakSelf = self;
    NSString *capturedVirtualDisplayID = [virtualDisplayID copy];
    RCTObjCSetObject(descriptor, terminationHandlerSelector, [^{
      RCTDisplayCore *strongSelf = weakSelf;
      if (strongSelf == nil) {
        return;
      }

      dispatch_async(dispatch_get_main_queue(), ^{
        NSMutableDictionary *record = [strongSelf.virtualDisplayRecords[capturedVirtualDisplayID] mutableCopy];
        if (![record isKindOfClass:NSMutableDictionary.class]) {
          return;
        }

        record[@"status"] = @"Terminated";
        record[@"mirrorTargetDisplayID"] = @"";
        record[@"mirrorSourceDisplayID"] = @"";
        record[@"mirrorMode"] = @"none";
        record[@"mirrorStatus"] = @"Not mirrored";
        record[@"lastError"] = @"Virtual display terminated by system";
        [strongSelf.virtualDisplays removeObjectForKey:capturedVirtualDisplayID];
        strongSelf.virtualDisplayRecords[capturedVirtualDisplayID] = record;
        [strongSelf persistVirtualDisplayRecords];
      });
    } copy]);
  }

  RCTObjCSetUnsignedInt(settings, RCTDisplayPrivateSelector(@"setHiDPI:"), isHiDpi ? 1 : 0);
  RCTObjCSetObject(settings, RCTDisplayPrivateSelector(@"setModes:"), @[ mode ]);

  id displayAllocation = ((id (*)(Class, SEL))objc_msgSend)(displayClass, @selector(alloc));
  id virtualDisplay =
      ((id (*)(id, SEL, id))objc_msgSend)(displayAllocation, displayInitSelector, descriptor);

  SEL applySettingsSelector = RCTDisplayPrivateSelector(@"applySettings:");
  if (virtualDisplay == nil || ![virtualDisplay respondsToSelector:applySettingsSelector]) {
    if (errorMessage != nil) {
      *errorMessage = @"Virtual display creation failed";
    }

    NSLog(@"[macDisplayBar] Virtual display creation failed: width=%lu height=%lu refreshRate=%.3f HiDPI=%@",
          (unsigned long)logicalWidth,
          (unsigned long)logicalHeight,
          normalizedRefreshRate,
          isHiDpi ? @"YES" : @"NO");
    return @{};
  }

  BOOL didApply = ((BOOL (*)(id, SEL, id))objc_msgSend)(virtualDisplay, applySettingsSelector, settings);

  if (!didApply) {
    if (errorMessage != nil) {
      *errorMessage = @"Virtual display settings rejected";
    }

    NSLog(@"[macDisplayBar] Virtual display settings rejected: width=%lu height=%lu refreshRate=%.3f HiDPI=%@",
          (unsigned long)logicalWidth,
          (unsigned long)logicalHeight,
          normalizedRefreshRate,
          isHiDpi ? @"YES" : @"NO");
    return @{};
  }

  NSString *displayID = [self visibleDisplayIDForVirtualDisplay:virtualDisplay];

  self.virtualDisplays[virtualDisplayID] = virtualDisplay;

  if (displayID.length == 0) {
    NSLog(@"[macDisplayBar] Virtual display activation pending: id=%@ width=%lu height=%lu refreshRate=%.3f HiDPI=%@",
          virtualDisplayID,
          (unsigned long)logicalWidth,
          (unsigned long)logicalHeight,
          normalizedRefreshRate,
          isHiDpi ? @"YES" : @"NO");
    return [self virtualDisplayRecordWithID:virtualDisplayID
                            targetDisplayID:targetDisplayID ?: @""
                                   displayID:@""
                      mirrorTargetDisplayID:@""
                      mirrorSourceDisplayID:@""
                                   mirrorMode:@"none"
                                 mirrorStatus:@"Not mirrored"
                                       name:name
                               serialNumber:serialNumber
                                      width:logicalWidth
                                     height:logicalHeight
                                refreshRate:normalizedRefreshRate
                                    isHiDpi:isHiDpi
                                     status:@"Creating"
                                  lastError:@""];
  }

  NSLog(@"[macDisplayBar] Virtual display created: id=%@ displayID=%@ width=%lu height=%lu refreshRate=%.3f HiDPI=%@",
        virtualDisplayID,
        displayID,
        (unsigned long)logicalWidth,
        (unsigned long)logicalHeight,
        normalizedRefreshRate,
        isHiDpi ? @"YES" : @"NO");

  return [self virtualDisplayRecordWithID:virtualDisplayID
                          targetDisplayID:targetDisplayID ?: @""
                                 displayID:displayID
                    mirrorTargetDisplayID:@""
                    mirrorSourceDisplayID:@""
                                 mirrorMode:@"none"
                               mirrorStatus:@"Not mirrored"
                                     name:name
                             serialNumber:serialNumber
                                    width:logicalWidth
                                   height:logicalHeight
                              refreshRate:normalizedRefreshRate
                                  isHiDpi:isHiDpi
                                   status:@"Created"
                                lastError:@""];
}


- (BOOL)activeDisplayListContainsDisplayID:(CGDirectDisplayID)displayID
{
  if (displayID == 0) {
    return NO;
  }

  uint32_t displayCount = 0;
  CGError countError = CGGetActiveDisplayList(0, NULL, &displayCount);

  if (countError != kCGErrorSuccess || displayCount == 0) {
    return NO;
  }

  NSMutableData *displayIDData = [NSMutableData dataWithLength:sizeof(CGDirectDisplayID) * displayCount];
  CGDirectDisplayID *displayIDs = (CGDirectDisplayID *)displayIDData.mutableBytes;
  CGError listError = CGGetActiveDisplayList(displayCount, displayIDs, &displayCount);

  if (listError != kCGErrorSuccess) {
    return NO;
  }

  for (uint32_t index = 0; index < displayCount; index++) {
    if (displayIDs[index] == displayID) {
      return YES;
    }
  }

  return NO;
}

- (BOOL)createVirtualHiDpiFallbackForDisplayIDString:(NSString *)targetDisplayID
                                               width:(NSUInteger)width
                                              height:(NSUInteger)height
                                         refreshRate:(double)refreshRate
                                        statusReason:(NSString *)statusReason
                                        errorMessage:(NSString **)errorMessage
{
  if (![NSThread isMainThread]) {
    __block BOOL didCreateFallback = NO;
    __block NSString *capturedError = nil;
    dispatch_sync(dispatch_get_main_queue(), ^{
      didCreateFallback = [self createVirtualHiDpiFallbackForDisplayIDString:targetDisplayID
                                                                       width:width
                                                                      height:height
                                                                 refreshRate:refreshRate
                                                                statusReason:statusReason
                                                                errorMessage:&capturedError];
    });
    if (errorMessage != nil) {
      *errorMessage = capturedError;
    }
    return didCreateFallback;
  }

  if (targetDisplayID.length == 0 || width == 0 || height == 0) {
    if (errorMessage != nil) {
      *errorMessage = @"Virtual HiDPI fallback target invalid";
    }
    return NO;
  }

  for (NSString *existingVirtualDisplayID in self.virtualDisplayRecords.allKeys) {
    NSDictionary *existingRecord = self.virtualDisplayRecords[existingVirtualDisplayID];

    if (![existingRecord isKindOfClass:NSDictionary.class]) {
      continue;
    }

    BOOL matchesTarget = [existingRecord[@"targetDisplayID"] isEqualToString:targetDisplayID];
    BOOL matchesSize = [existingRecord[@"width"] unsignedIntegerValue] == width &&
        [existingRecord[@"height"] unsignedIntegerValue] == height;
    BOOL matchesRefresh = fabs([existingRecord[@"refreshRate"] doubleValue] - refreshRate) < 0.5;
    BOOL matchesScale = [existingRecord[@"isHiDpi"] boolValue];

    if (matchesTarget && matchesSize && matchesRefresh && matchesScale) {
      NSString *liveSourceDisplayID = [self visibleDisplayIDForVirtualDisplay:self.virtualDisplays[existingVirtualDisplayID]];

      if ([existingRecord[@"status"] isEqualToString:@"Creating"]) {
        NSMutableDictionary *pendingRecord = [existingRecord mutableCopy];
        pendingRecord[@"mirrorTargetDisplayID"] = targetDisplayID;
        pendingRecord[@"mirrorMode"] = @"target-mirrors-virtual";
        pendingRecord[@"mirrorStatus"] = @"Mirror pending";
        pendingRecord[@"lastError"] = @"";
        self.virtualDisplayRecords[existingVirtualDisplayID] = pendingRecord;
        [self persistVirtualDisplayRecords];
        [self scheduleVirtualDisplayActivationRetryForID:existingVirtualDisplayID wantsMirror:YES];
        if (errorMessage != nil) {
          *errorMessage = @"Virtual HiDPI fallback creating";
        }
        NSLog(@"[macDisplayBar] Generated HiDPI virtual fallback pending reuse: targetDisplayID=%@ virtualDisplayID=%@ reason=%@",
              targetDisplayID,
              existingVirtualDisplayID,
              statusReason ?: @"");
        return YES;
      }

      if (liveSourceDisplayID.length == 0 ||
          [existingRecord[@"status"] isEqualToString:@"Terminated"]) {
        NSLog(@"[macDisplayBar] Generated HiDPI virtual fallback skipped stale record: targetDisplayID=%@ virtualDisplayID=%@ status=%@",
              targetDisplayID,
              existingVirtualDisplayID,
              existingRecord[@"status"] ?: @"");
        continue;
      }

      NSString *mirrorError = nil;
      NSDictionary *updatedRecord = [self recordByApplyingVirtualMirrorForID:existingVirtualDisplayID
                                                                      record:existingRecord
                                                                errorMessage:&mirrorError];
      self.virtualDisplayRecords[existingVirtualDisplayID] = updatedRecord;
      [self persistVirtualDisplayRecords];

      BOOL didMirror = [updatedRecord[@"mirrorStatus"] isEqualToString:@"Mirrored to target"];
      if (!didMirror && errorMessage != nil) {
        *errorMessage = mirrorError ?: @"Virtual HiDPI fallback mirror failed";
      }

      NSLog(@"[macDisplayBar] Generated HiDPI virtual fallback reused: targetDisplayID=%@ virtualDisplayID=%@ width=%lu height=%lu refreshRate=%.3f mirrored=%@ reason=%@",
            targetDisplayID,
            existingVirtualDisplayID,
            (unsigned long)width,
            (unsigned long)height,
            refreshRate,
            didMirror ? @"YES" : @"NO",
            statusReason ?: @"");
      return didMirror;
    }
  }

  NSString *virtualDisplayID = [[NSUUID UUID] UUIDString];
  NSString *creationError = nil;
  NSNumber *serialNumber = @(arc4random());
  NSDictionary *record = [self createVirtualDisplayRecordWithID:virtualDisplayID
                                                targetDisplayID:targetDisplayID
                                                   serialNumber:serialNumber
                                                         width:width
                                                        height:height
                                                   refreshRate:refreshRate
                                                       isHiDpi:YES
                                                  errorMessage:&creationError];

  if (record.count == 0) {
    if (errorMessage != nil) {
      *errorMessage = creationError ?: @"Virtual HiDPI fallback creation failed";
    }
    return NO;
  }

  if ([record[@"status"] isEqualToString:@"Creating"]) {
    NSMutableDictionary *pendingRecord = [record mutableCopy];
    pendingRecord[@"mirrorTargetDisplayID"] = targetDisplayID;
    pendingRecord[@"mirrorMode"] = @"target-mirrors-virtual";
    pendingRecord[@"mirrorStatus"] = @"Mirror pending";
    pendingRecord[@"lastError"] = @"";
    self.virtualDisplayRecords[virtualDisplayID] = pendingRecord;
    [self persistVirtualDisplayRecords];
    [self scheduleVirtualDisplayActivationRetryForID:virtualDisplayID wantsMirror:YES];
    if (errorMessage != nil) {
      *errorMessage = @"Virtual HiDPI fallback creating";
    }
    NSLog(@"[macDisplayBar] Generated HiDPI virtual fallback pending activation: targetDisplayID=%@ virtualDisplayID=%@ width=%lu height=%lu refreshRate=%.3f reason=%@",
          targetDisplayID,
          virtualDisplayID,
          (unsigned long)width,
          (unsigned long)height,
          refreshRate,
          statusReason ?: @"");
    return YES;
  }

  NSString *mirrorError = nil;
  NSDictionary *updatedRecord = [self recordByApplyingVirtualMirrorForID:virtualDisplayID
                                                                  record:record
                                                            errorMessage:&mirrorError];
  self.virtualDisplayRecords[virtualDisplayID] = updatedRecord;
  [self persistVirtualDisplayRecords];

  BOOL didMirror = [updatedRecord[@"mirrorStatus"] isEqualToString:@"Mirrored to target"];
  if (!didMirror && errorMessage != nil) {
    *errorMessage = mirrorError ?: @"Virtual HiDPI fallback mirror failed";
  }
  if (!didMirror) {
    [self removeVirtualDisplay:virtualDisplayID];
  }

  NSLog(@"[macDisplayBar] Generated HiDPI virtual fallback created: targetDisplayID=%@ virtualDisplayID=%@ width=%lu height=%lu refreshRate=%.3f mirrored=%@ reason=%@",
        targetDisplayID,
        virtualDisplayID,
        (unsigned long)width,
        (unsigned long)height,
        refreshRate,
        didMirror ? @"YES" : @"NO",
        statusReason ?: @"");
  return didMirror;
}

- (BOOL)configureDisplayID:(CGDirectDisplayID)displayID
           mirrorOfDisplay:(CGDirectDisplayID)sourceDisplayID
              errorMessage:(NSString **)errorMessage
{
  if (displayID == 0) {
    if (errorMessage != nil) {
      *errorMessage = @"Mirror target display is unavailable";
    }

    return NO;
  }

  CGDisplayConfigRef config = NULL;
  CGError beginError = CGBeginDisplayConfiguration(&config);

  if (beginError != kCGErrorSuccess || config == NULL) {
    if (errorMessage != nil) {
      *errorMessage = [NSString stringWithFormat:@"Mirror configuration start failed: 0x%08x", beginError];
    }

    return NO;
  }

  CGError mirrorError = CGConfigureDisplayMirrorOfDisplay(config, displayID, sourceDisplayID);

  if (mirrorError != kCGErrorSuccess) {
    CGCancelDisplayConfiguration(config);
    if (errorMessage != nil) {
      *errorMessage = [NSString stringWithFormat:@"Mirror configuration failed: 0x%08x", mirrorError];
    }

    NSLog(@"[macDisplayBar] Virtual display mirror configuration failed: target=%u source=%u error=0x%08x",
          displayID,
          sourceDisplayID,
          mirrorError);
    return NO;
  }

  CGError completeError = CGCompleteDisplayConfiguration(config, kCGConfigureForSession);

  if (completeError != kCGErrorSuccess) {
    if (errorMessage != nil) {
      *errorMessage = [NSString stringWithFormat:@"Mirror apply failed: 0x%08x", completeError];
    }

    NSLog(@"[macDisplayBar] Virtual display mirror apply failed: target=%u source=%u error=0x%08x",
          displayID,
          sourceDisplayID,
          completeError);
    return NO;
  }

  CGDirectDisplayID actualSourceDisplayID = CGDisplayMirrorsDisplay(displayID);
  if (actualSourceDisplayID != sourceDisplayID) {
    if (errorMessage != nil) {
      *errorMessage = [NSString stringWithFormat:@"Mirror post-check failed: expected %u actual %u",
                                                 sourceDisplayID,
                                                 actualSourceDisplayID];
    }

    NSLog(@"[macDisplayBar] Virtual display mirror post-check failed: target=%u expectedSource=%u actualSource=%u",
          displayID,
          sourceDisplayID,
          actualSourceDisplayID);
    return NO;
  }

  NSLog(@"[macDisplayBar] Virtual display mirror configured: target=%u source=%u",
        displayID,
        sourceDisplayID);
  return YES;
}


- (NSDictionary *)recordByApplyingVirtualMirrorForID:(NSString *)virtualDisplayID
                                              record:(NSDictionary *)record
                                        errorMessage:(NSString **)errorMessage
{
  return [self recordByApplyingVirtualMirrorForID:virtualDisplayID
                                           record:record
                                        restoring:NO
                                     errorMessage:errorMessage];
}


- (NSDictionary *)recordByApplyingVirtualMirrorForID:(NSString *)virtualDisplayID
                                              record:(NSDictionary *)record
                                           restoring:(BOOL)restoring
                                        errorMessage:(NSString **)errorMessage
{
  NSString *targetDisplayID = [self resolvedVirtualMirrorTargetDisplayIDForRecord:record
                                                                        restoring:restoring
                                                                     errorMessage:errorMessage];
  NSString *sourceDisplayID = [record[@"displayID"] isKindOfClass:NSString.class] ? record[@"displayID"] : @"";
  NSMutableDictionary *updatedRecord = [record mutableCopy];
  NSString *liveSourceDisplayID = [self visibleDisplayIDForVirtualDisplay:self.virtualDisplays[virtualDisplayID]];

  if (targetDisplayID.length > 0) {
    updatedRecord[@"targetDisplayID"] = targetDisplayID;
    updatedRecord[@"targetIdentityKey"] = [self identityKeyForDisplayID:(CGDirectDisplayID)targetDisplayID.integerValue];
  }

  if (liveSourceDisplayID.length > 0 && ![liveSourceDisplayID isEqualToString:sourceDisplayID]) {
    sourceDisplayID = liveSourceDisplayID;
    updatedRecord[@"displayID"] = liveSourceDisplayID;
  }

  if (targetDisplayID.length == 0 || sourceDisplayID.length == 0) {
    updatedRecord[@"mirrorTargetDisplayID"] = @"";
    updatedRecord[@"mirrorSourceDisplayID"] = @"";
    updatedRecord[@"mirrorMode"] = @"none";
    updatedRecord[@"mirrorStatus"] = @"Not mirrored";
    return updatedRecord;
  }

  BOOL didMirror = [self configureDisplayID:(CGDirectDisplayID)targetDisplayID.integerValue
                            mirrorOfDisplay:(CGDirectDisplayID)sourceDisplayID.integerValue
                               errorMessage:errorMessage];

  updatedRecord[@"mirrorTargetDisplayID"] = didMirror ? targetDisplayID : (record[@"mirrorTargetDisplayID"] ?: @"");
  updatedRecord[@"mirrorSourceDisplayID"] = didMirror ? sourceDisplayID : (record[@"mirrorSourceDisplayID"] ?: @"");
  updatedRecord[@"mirrorMode"] = didMirror ? @"target-mirrors-virtual" : (record[@"mirrorMode"] ?: @"none");
  updatedRecord[@"mirrorStatus"] = didMirror ? @"Mirrored to target" : @"Mirror failed";
  updatedRecord[@"status"] = didMirror ? @"Created and mirrored" : (record[@"status"] ?: @"Created");
  if (didMirror) {
    updatedRecord[@"mirrorUpdatedAt"] = @([[NSDate date] timeIntervalSince1970]);
  }
  NSString *mirrorError = errorMessage != nil ? *errorMessage : nil;
  updatedRecord[@"lastError"] = didMirror ? @"" : (mirrorError ?: @"Virtual display mirror failed");

  if (didMirror) {
    for (NSString *otherVirtualDisplayID in self.virtualDisplayRecords.allKeys) {
      if ([otherVirtualDisplayID isEqualToString:virtualDisplayID]) {
        continue;
      }

      NSDictionary *otherRecord = self.virtualDisplayRecords[otherVirtualDisplayID];
      if (![otherRecord isKindOfClass:NSDictionary.class]) {
        continue;
      }

      NSString *otherMirrorTargetID = [otherRecord[@"mirrorTargetDisplayID"] isKindOfClass:NSString.class]
          ? otherRecord[@"mirrorTargetDisplayID"]
          : @"";

      if (![otherMirrorTargetID isEqualToString:targetDisplayID]) {
        continue;
      }

      NSMutableDictionary *clearedRecord = [otherRecord mutableCopy];
      clearedRecord[@"mirrorTargetDisplayID"] = @"";
      clearedRecord[@"mirrorSourceDisplayID"] = @"";
      clearedRecord[@"mirrorMode"] = @"none";
      clearedRecord[@"mirrorStatus"] = @"Not mirrored";
      clearedRecord[@"lastError"] = @"";
      self.virtualDisplayRecords[otherVirtualDisplayID] = clearedRecord;
      NSLog(@"[macDisplayBar] Virtual display mirror stale record cleared: activeID=%@ staleID=%@ target=%@",
            virtualDisplayID,
            otherVirtualDisplayID,
            targetDisplayID);
    }
  }

  return updatedRecord;
}


- (NSString *)resolvedVirtualMirrorTargetDisplayIDForRecord:(NSDictionary *)record
                                                  restoring:(BOOL)restoring
                                               errorMessage:(NSString **)errorMessage
{
  NSString *targetDisplayID = [record[@"targetDisplayID"] isKindOfClass:NSString.class] ? record[@"targetDisplayID"] : @"";
  NSString *targetIdentityKey = [record[@"targetIdentityKey"] isKindOfClass:NSString.class] ? record[@"targetIdentityKey"] : @"";

  if (targetIdentityKey.length > 0) {
    NSString *matchedDisplayID = [self activeDisplayIDStringForIdentityKey:targetIdentityKey];

    if (matchedDisplayID.length > 0) {
      return matchedDisplayID;
    }

    if (errorMessage != nil) {
      *errorMessage = @"Virtual mirror target identity unavailable";
    }

    NSLog(@"[macDisplayBar] Virtual display mirror target identity unavailable: storedTarget=%@ identityKey=%@ restoring=%@",
          targetDisplayID,
          targetIdentityKey,
          restoring ? @"YES" : @"NO");
    return @"";
  }

  if (restoring) {
    if (errorMessage != nil) {
      *errorMessage = @"Virtual mirror restore skipped because target identity is missing";
    }

    NSLog(@"[macDisplayBar] Virtual display mirror restore skipped: target identity missing storedTarget=%@",
          targetDisplayID);
    return @"";
  }

  if (![self activeDisplayListContainsDisplayID:(CGDirectDisplayID)targetDisplayID.integerValue]) {
    if (errorMessage != nil) {
      *errorMessage = @"Virtual mirror target display unavailable";
    }

    NSLog(@"[macDisplayBar] Virtual display mirror target unavailable: storedTarget=%@",
          targetDisplayID);
    return @"";
  }

  return targetDisplayID;
}


- (NSString *)resolvedVirtualTargetDisplayIDForRecord:(NSDictionary *)record
{
  NSString *targetDisplayID = [record[@"targetDisplayID"] isKindOfClass:NSString.class] ? record[@"targetDisplayID"] : @"";
  NSString *targetIdentityKey = [record[@"targetIdentityKey"] isKindOfClass:NSString.class] ? record[@"targetIdentityKey"] : @"";

  if (targetIdentityKey.length > 0) {
    NSString *matchedDisplayID = [self activeDisplayIDStringForIdentityKey:targetIdentityKey];

    if (matchedDisplayID.length > 0) {
      return matchedDisplayID;
    }

    NSLog(@"[macDisplayBar] Virtual display target identity unavailable: storedTarget=%@ identityKey=%@",
          targetDisplayID,
          targetIdentityKey);
    return @"";
  }

  if ([self displayIDStringIsActive:targetDisplayID]) {
    return targetDisplayID;
  }

  return @"";
}

- (NSDictionary *)virtualDisplayRecordWithID:(NSString *)virtualDisplayID
                             targetDisplayID:(NSString *)targetDisplayID
                                   displayID:(NSString *)displayID
                      mirrorTargetDisplayID:(NSString *)mirrorTargetDisplayID
                      mirrorSourceDisplayID:(NSString *)mirrorSourceDisplayID
                                   mirrorMode:(NSString *)mirrorMode
                                 mirrorStatus:(NSString *)mirrorStatus
                                        name:(NSString *)name
                                serialNumber:(NSNumber *)serialNumber
                                       width:(double)width
                                      height:(double)height
                                 refreshRate:(double)refreshRate
                                     isHiDpi:(BOOL)isHiDpi
                                      status:(NSString *)status
                                   lastError:(NSString *)lastError
{
  return @{
    @"id" : virtualDisplayID ?: @"",
    @"targetDisplayID" : targetDisplayID ?: @"",
    @"targetIdentityKey" : [self displayIDStringIsActive:targetDisplayID ?: @""]
        ? [self identityKeyForDisplayID:(CGDirectDisplayID)targetDisplayID.integerValue]
        : @"",
    @"displayID" : displayID ?: @"",
    @"mirrorTargetDisplayID" : mirrorTargetDisplayID ?: @"",
    @"mirrorSourceDisplayID" : mirrorSourceDisplayID ?: @"",
    @"mirrorMode" : mirrorMode ?: @"none",
    @"mirrorStatus" : mirrorStatus ?: @"Not mirrored",
    @"mirrorUpdatedAt" : @0,
    @"name" : name ?: @"macDisplayBar Virtual Display",
    @"serialNumber" : @(serialNumber.unsignedIntValue),
    @"width" : @(MAX(width, 1)),
    @"height" : @(MAX(height, 1)),
    @"refreshRate" : @(refreshRate > 0 ? refreshRate : 60),
    @"isHiDpi" : @(isHiDpi),
    @"status" : status ?: @"Unknown",
    @"lastError" : lastError ?: @"",
  };
}


- (NSString *)visibleDisplayIDForVirtualDisplay:(id)virtualDisplay
{
  SEL displayIDSelector = RCTDisplayPrivateSelector(@"displayID");

  if (virtualDisplay == nil || ![virtualDisplay respondsToSelector:displayIDSelector]) {
    return @"";
  }

  NSUInteger maxAttempts = [NSThread isMainThread] ? 1 : 10;

  for (NSUInteger attempt = 0; attempt < maxAttempts; attempt++) {
    if (attempt > 0) {
      [NSThread sleepForTimeInterval:0.1];
    }

    unsigned int directDisplayID = ((unsigned int (*)(id, SEL))objc_msgSend)(virtualDisplay, displayIDSelector);

    if (directDisplayID != 0 && [self activeDisplayListContainsDisplayID:directDisplayID]) {
      return [NSString stringWithFormat:@"%u", directDisplayID];
    }
  }

  return @"";
}


- (NSArray<NSDictionary *> *)virtualDisplaySummaries
{
  if (![NSThread isMainThread]) {
    __block NSArray<NSDictionary *> *summaries = nil;
    dispatch_sync(dispatch_get_main_queue(), ^{
      summaries = [self virtualDisplaySummaries];
    });
    return summaries ?: @[];
  }

  NSMutableArray<NSDictionary *> *summaries = [NSMutableArray arrayWithCapacity:self.virtualDisplayRecords.count];

  for (NSString *virtualDisplayID in self.virtualDisplayRecords) {
    NSDictionary *record = self.virtualDisplayRecords[virtualDisplayID];

    if ([record isKindOfClass:NSDictionary.class]) {
      NSMutableDictionary *summary = [record mutableCopy];
      NSString *resolvedTargetDisplayID = [self resolvedVirtualTargetDisplayIDForRecord:record];

      if (resolvedTargetDisplayID.length > 0) {
        summary[@"targetDisplayID"] = resolvedTargetDisplayID;
      }

      [summaries addObject:summary];
    }
  }

  [summaries sortUsingComparator:^NSComparisonResult(NSDictionary *left, NSDictionary *right) {
    return [left[@"name"] compare:right[@"name"]];
  }];

  return summaries;
}


- (void)persistVirtualDisplayRecords
{
  [[NSUserDefaults standardUserDefaults] setObject:self.virtualDisplayRecords
                                            forKey:RCTDisplayVirtualDisplaysDefaultsKey];
}

- (void)restoreManagedVirtualDisplays
{
  if (![NSThread isMainThread]) {
    dispatch_async(dispatch_get_main_queue(), ^{
      [self restoreManagedVirtualDisplays];
    });
    return;
  }

  NSArray<NSString *> *virtualDisplayIDs =
      [self.virtualDisplayRecords.allKeys sortedArrayUsingComparator:^NSComparisonResult(NSString *leftID, NSString *rightID) {
        NSDictionary *leftRecord = self.virtualDisplayRecords[leftID];
        NSDictionary *rightRecord = self.virtualDisplayRecords[rightID];
        double leftUpdatedAt = [leftRecord[@"mirrorUpdatedAt"] doubleValue];
        double rightUpdatedAt = [rightRecord[@"mirrorUpdatedAt"] doubleValue];

        if (leftUpdatedAt > rightUpdatedAt) {
          return NSOrderedAscending;
        }

        if (leftUpdatedAt < rightUpdatedAt) {
          return NSOrderedDescending;
        }

        return [leftID compare:rightID];
      }];
  NSMutableSet<NSString *> *restoredMirrorTargets = [NSMutableSet new];

  for (NSString *virtualDisplayID in virtualDisplayIDs) {
    NSDictionary *record = self.virtualDisplayRecords[virtualDisplayID];

    if (![record isKindOfClass:NSDictionary.class] || [record[@"status"] isEqualToString:@"Create failed"]) {
      continue;
    }

    NSString *errorMessage = nil;
    NSString *resolvedTargetDisplayID = [self resolvedVirtualTargetDisplayIDForRecord:record];

    if (resolvedTargetDisplayID.length == 0) {
      NSMutableDictionary *pausedRecord = [record mutableCopy];
      pausedRecord[@"displayID"] = @"";
      pausedRecord[@"mirrorTargetDisplayID"] = @"";
      pausedRecord[@"mirrorSourceDisplayID"] = @"";
      pausedRecord[@"mirrorMode"] = @"none";
      pausedRecord[@"mirrorStatus"] = @"Not mirrored";
      pausedRecord[@"status"] = @"Paused";
      pausedRecord[@"lastError"] = @"Target unavailable";
      self.virtualDisplayRecords[virtualDisplayID] = pausedRecord;
      continue;
    }

    NSDictionary *restoredRecord = [self createVirtualDisplayRecordWithID:virtualDisplayID
                                                   targetDisplayID:resolvedTargetDisplayID
                                                      serialNumber:record[@"serialNumber"] ?: @(arc4random())
                                                            width:[record[@"width"] doubleValue]
                                                           height:[record[@"height"] doubleValue]
                                                      refreshRate:[record[@"refreshRate"] doubleValue]
                                                          isHiDpi:[record[@"isHiDpi"] boolValue]
                                                     errorMessage:&errorMessage];

    if (restoredRecord.count > 0) {
      NSMutableDictionary *restoredMutableRecord = [restoredRecord mutableCopy];
      restoredMutableRecord[@"targetIdentityKey"] = [record[@"targetIdentityKey"] isKindOfClass:NSString.class]
          ? record[@"targetIdentityKey"]
          : @"";
      restoredRecord = restoredMutableRecord;

      NSString *mirrorMode = [record[@"mirrorMode"] isKindOfClass:NSString.class] ? record[@"mirrorMode"] : @"";
      NSString *mirrorTargetDisplayID = [record[@"mirrorTargetDisplayID"] isKindOfClass:NSString.class]
          ? record[@"mirrorTargetDisplayID"]
          : @"";
      NSString *resolvedMirrorTargetDisplayID = @"";

      if ([mirrorMode isEqualToString:@"target-mirrors-virtual"] && mirrorTargetDisplayID.length > 0) {
        resolvedMirrorTargetDisplayID = [self resolvedVirtualMirrorTargetDisplayIDForRecord:restoredRecord
                                                                                  restoring:YES
                                                                               errorMessage:&errorMessage];
      }

      BOOL wantsMirrorRestore = [mirrorMode isEqualToString:@"target-mirrors-virtual"] &&
          resolvedMirrorTargetDisplayID.length > 0 &&
          ![restoredMirrorTargets containsObject:resolvedMirrorTargetDisplayID];

      if (wantsMirrorRestore && [restoredRecord[@"status"] isEqualToString:@"Creating"]) {
        NSMutableDictionary *pendingRecord = [restoredRecord mutableCopy];
        pendingRecord[@"mirrorTargetDisplayID"] = resolvedMirrorTargetDisplayID;
        pendingRecord[@"mirrorMode"] = @"target-mirrors-virtual";
        pendingRecord[@"mirrorStatus"] = @"Mirror pending";
        pendingRecord[@"lastError"] = @"";
        restoredRecord = pendingRecord;
        [self scheduleVirtualDisplayActivationRetryForID:virtualDisplayID wantsMirror:YES];
      } else if (wantsMirrorRestore) {
        restoredRecord = [self recordByApplyingVirtualMirrorForID:virtualDisplayID
                                                           record:restoredRecord
                                                        restoring:YES
                                                     errorMessage:&errorMessage];
        if ([restoredRecord[@"mirrorStatus"] isEqualToString:@"Mirrored to target"]) {
          [restoredMirrorTargets addObject:restoredRecord[@"mirrorTargetDisplayID"] ?: resolvedMirrorTargetDisplayID];
        }
      } else {
        NSMutableDictionary *stoppedRecord = [restoredRecord mutableCopy];
        stoppedRecord[@"mirrorTargetDisplayID"] = @"";
        stoppedRecord[@"mirrorSourceDisplayID"] = @"";
        stoppedRecord[@"mirrorMode"] = @"none";
        stoppedRecord[@"mirrorStatus"] = @"Not mirrored";
        stoppedRecord[@"lastError"] = @"";
        restoredRecord = stoppedRecord;
      }

      self.virtualDisplayRecords[virtualDisplayID] = restoredRecord;
      if ([restoredRecord[@"status"] isEqualToString:@"Creating"]) {
        [self scheduleVirtualDisplayActivationRetryForID:virtualDisplayID
                                             wantsMirror:[restoredRecord[@"mirrorMode"] isEqualToString:@"target-mirrors-virtual"]];
      }
    } else {
      self.virtualDisplayRecords[virtualDisplayID] =
          [self virtualDisplayRecordWithID:virtualDisplayID
                           targetDisplayID:resolvedTargetDisplayID.length > 0 ? resolvedTargetDisplayID : (record[@"targetDisplayID"] ?: @"")
                                 displayID:@""
                    mirrorTargetDisplayID:@""
                    mirrorSourceDisplayID:@""
                                 mirrorMode:@"none"
                               mirrorStatus:@"Not mirrored"
                                      name:record[@"name"] ?: @"macDisplayBar Virtual Display"
                              serialNumber:record[@"serialNumber"] ?: @(arc4random())
                                     width:[record[@"width"] doubleValue]
                                    height:[record[@"height"] doubleValue]
                               refreshRate:[record[@"refreshRate"] doubleValue]
                                   isHiDpi:[record[@"isHiDpi"] boolValue]
                                    status:@"Restore failed"
                                 lastError:errorMessage ?: @"Virtual display restore failed"];
    }
  }

  [self persistVirtualDisplayRecords];
}

