- (NSArray<NSData *> *)scaleResolutionsForCustomResolutions:(NSArray<NSDictionary *> *)customResolutions
{
  NSMutableArray<NSData *> *scaleResolutions = [NSMutableArray new];
  NSMutableSet<NSData *> *seenResolutions = [NSMutableSet new];
  NSDictionary *hiDpiSeedResolution = nil;
  NSUInteger hiDpiSeedArea = 0;

  for (NSDictionary *resolution in customResolutions) {
    NSUInteger width = [resolution[@"width"] unsignedIntegerValue];
    NSUInteger height = [resolution[@"height"] unsignedIntegerValue];

    if (width == 0 || height == 0) {
      continue;
    }

    if ([resolution[@"isHiDpi"] boolValue]) {
      NSUInteger area = width * height;

      if (hiDpiSeedResolution == nil || area > hiDpiSeedArea) {
        hiDpiSeedResolution = resolution;
        hiDpiSeedArea = area;
      }
      continue;
    }

    NSData *data = MDBScaleResolutionData(width, height);

    if ([seenResolutions containsObject:data]) {
      continue;
    }

    [seenResolutions addObject:data];
    [scaleResolutions addObject:data];
  }

  if (hiDpiSeedResolution != nil) {
    MDBAppendOneKeyHiDpiScaleResolutionFamily(scaleResolutions,
                                              seenResolutions,
                                              [hiDpiSeedResolution[@"width"] unsignedIntegerValue],
                                              [hiDpiSeedResolution[@"height"] unsignedIntegerValue]);
  }

  return scaleResolutions;
}


- (BOOL)exposedGeneratedHiDpiRecipeExistsForDisplayID:(CGDirectDisplayID)displayID
                                                width:(NSUInteger)width
                                               height:(NSUInteger)height
{
  NSDictionary *options = @{(__bridge NSString *)kCGDisplayShowDuplicateLowResolutionModes : @YES};
  CFArrayRef copiedModes = CGDisplayCopyAllDisplayModes(displayID, (__bridge CFDictionaryRef)options);

  if (copiedModes == NULL) {
    return NO;
  }

  NSArray *modes = CFBridgingRelease(copiedModes);
  NSMutableSet<NSString *> *hiDpiResolutionKeys = [NSMutableSet new];

  for (id item in modes) {
    CGDisplayModeRef candidate = (__bridge CGDisplayModeRef)item;

    if (CGDisplayModeGetPixelWidth(candidate) <= CGDisplayModeGetWidth(candidate)) {
      continue;
    }

    [hiDpiResolutionKeys addObject:MDBIntegerPairKey(CGDisplayModeGetWidth(candidate), CGDisplayModeGetHeight(candidate))];
  }

  return MDBOneKeyHiDpiRecipeIsExposed(hiDpiResolutionKeys, width, height);
}


- (BOOL)installedOneKeyHiDpiRecipeExistsForDisplayID:(CGDirectDisplayID)displayID
                                               width:(NSUInteger)width
                                              height:(NSUInteger)height
{
  NSString *vendorDirectoryName = [NSString stringWithFormat:@"DisplayVendorID-%x", CGDisplayVendorNumber(displayID)];
  NSString *productFileName = [NSString stringWithFormat:@"DisplayProductID-%x", CGDisplayModelNumber(displayID)];
  NSURL *overrideURL = [[[NSURL fileURLWithPath:RCTDisplayOverrideInstallDirectory isDirectory:YES]
      URLByAppendingPathComponent:vendorDirectoryName
                      isDirectory:YES] URLByAppendingPathComponent:productFileName];
  NSData *plistData = [NSData dataWithContentsOfURL:overrideURL];

  if (plistData.length == 0) {
    return NO;
  }

  NSError *error = nil;
  NSDictionary *manifest = [NSPropertyListSerialization propertyListWithData:plistData
                                                                     options:NSPropertyListImmutable
                                                                      format:nil
                                                                       error:&error];

  if (![manifest isKindOfClass:NSDictionary.class] || error != nil) {
    return NO;
  }

  if ([manifest[@"DisplayVendorID"] unsignedIntValue] != CGDisplayVendorNumber(displayID) ||
      [manifest[@"DisplayProductID"] unsignedIntValue] != CGDisplayModelNumber(displayID)) {
    return NO;
  }

  NSArray *installedScaleResolutions = manifest[@"scale-resolutions"];

  if (![installedScaleResolutions isKindOfClass:NSArray.class]) {
    return NO;
  }

  NSMutableArray<NSData *> *expectedScaleResolutions = [NSMutableArray new];
  NSMutableSet<NSData *> *expectedSet = [NSMutableSet new];
  MDBAppendOneKeyHiDpiScaleResolutionFamily(expectedScaleResolutions, expectedSet, width, height);
  NSSet *installedSet = [NSSet setWithArray:installedScaleResolutions];

  for (NSData *expectedResolution in expectedScaleResolutions) {
    if (![installedSet containsObject:expectedResolution]) {
      return NO;
    }
  }

  return YES;
}


- (BOOL)isSub4KHiDpiUnlockTargetWithWidth:(NSUInteger)width height:(NSUInteger)height
{
  return width < RCTDisplay4KWidth || height < RCTDisplay4KHeight;
}


- (NSString *)hiDpiUnlockTargetClassWithWidth:(NSUInteger)width height:(NSUInteger)height
{
  return [self isSub4KHiDpiUnlockTargetWithWidth:width height:height] ? @"sub4k" : @"4k-or-above";
}

- (NSData *)edidDataForDisplayID:(CGDirectDisplayID)displayID
{
  uint32_t vendorID = CGDisplayVendorNumber(displayID);
  uint32_t productID = CGDisplayModelNumber(displayID);
  uint32_t serialNumber = CGDisplaySerialNumber(displayID);
  io_iterator_t iterator = MACH_PORT_NULL;
  kern_return_t result = IOServiceGetMatchingServices(kIOMainPortDefault, IOServiceMatching("IODisplayConnect"), &iterator);

  if (result != KERN_SUCCESS || iterator == MACH_PORT_NULL) {
    return nil;
  }

  io_service_t service = MACH_PORT_NULL;

  while ((service = IOIteratorNext(iterator)) != MACH_PORT_NULL) {
    NSDictionary *info = CFBridgingRelease(IODisplayCreateInfoDictionary(service, kIODisplayOnlyPreferredName));
    NSNumber *candidateVendorID = info[[NSString stringWithUTF8String:kDisplayVendorID]];
    NSNumber *candidateProductID = info[[NSString stringWithUTF8String:kDisplayProductID]];
    NSNumber *candidateSerialNumber = info[[NSString stringWithUTF8String:kDisplaySerialNumber]];
    BOOL vendorMatches = candidateVendorID.unsignedIntValue == vendorID;
    BOOL productMatches = candidateProductID.unsignedIntValue == productID;
    BOOL serialMatches = serialNumber == 0 || candidateSerialNumber.unsignedIntValue == serialNumber;

    if (vendorMatches && productMatches && serialMatches) {
      NSData *edidData = CFBridgingRelease(IORegistryEntryCreateCFProperty(
          service, CFSTR(kIODisplayEDIDKey), kCFAllocatorDefault, kNilOptions));
      IOObjectRelease(service);
      IOObjectRelease(iterator);
      return edidData;
    }

    IOObjectRelease(service);
  }

  IOObjectRelease(iterator);
  return nil;
}


- (NSString *)writeOverrideBundleForDisplayIDString:(NSString *)displayID
{
  return [self writeOverrideBundleForDisplayIDString:displayID includeEdid:YES];
}


- (NSString *)writeOverrideBundleForDisplayIDString:(NSString *)displayID includeEdid:(BOOL)includeEdid
{
  return [self writeOverrideBundleForDisplayIDString:displayID
                                         includeEdid:includeEdid
                                   customResolutions:[self customResolutionRequestsForDisplayIDString:displayID]];
}


- (NSString *)writeOverrideBundleForDisplayIDString:(NSString *)displayID
                                        includeEdid:(BOOL)includeEdid
                                  customResolutions:(NSArray<NSDictionary *> *)customResolutions
{
  CGDirectDisplayID directDisplayID = (CGDirectDisplayID)displayID.integerValue;

  if (directDisplayID == 0 || ![self activeDisplayListContainsDisplayID:directDisplayID]) {
    NSLog(@"[macDisplayBar] Display override bundle skipped: displayID=%@ reason=invalid or inactive display",
          displayID);
    return @"";
  }

  uint32_t vendorID = CGDisplayVendorNumber(directDisplayID);
  uint32_t productID = CGDisplayModelNumber(directDisplayID);

  if (vendorID == 0 && productID == 0) {
    NSLog(@"[macDisplayBar] Display override bundle skipped: displayID=%@ reason=missing vendor/product identity",
          displayID);
    return @"";
  }

  NSString *edidOverridePath = self.edidOverridePaths[displayID] ?: @"";
  NSString *vendorDirectoryName = [NSString stringWithFormat:@"DisplayVendorID-%x", vendorID];
  NSString *productFileName = [NSString stringWithFormat:@"DisplayProductID-%x", productID];
  NSURL *baseDirectoryURL =
      [[[NSFileManager defaultManager] URLsForDirectory:NSDocumentDirectory inDomains:NSUserDomainMask].firstObject
          URLByAppendingPathComponent:@"MacDisplayBar/Overrides"
                          isDirectory:YES];
  NSURL *vendorDirectoryURL = [baseDirectoryURL URLByAppendingPathComponent:vendorDirectoryName isDirectory:YES];
  NSURL *fileURL = [vendorDirectoryURL URLByAppendingPathComponent:productFileName];

  [[NSFileManager defaultManager] createDirectoryAtURL:vendorDirectoryURL
                           withIntermediateDirectories:YES
                                            attributes:nil
                                                 error:nil];

  NSMutableDictionary *manifest = [@{
    @"DisplayVendorID" : @(vendorID),
    @"DisplayProductID" : @(productID),
    @"target-default-ppmm" : @10.0699301,
  } mutableCopy];
  NSMutableArray<NSData *> *scaleResolutions = [[self scaleResolutionsForCustomResolutions:customResolutions] mutableCopy];
  NSMutableSet<NSData *> *seenScaleResolutions = [NSMutableSet setWithArray:scaleResolutions];
  BOOL flexibleScalingEnabled = [self flexibleScalingEnabledForDisplayIDString:displayID];
  BOOL hasPanelResolutionOverride = [self nativePanelResolutionOverrideExistsForDisplayIDString:displayID];
  NSDictionary *nativePanelResolution = [self nativePanelResolutionForDisplayID:directDisplayID displayIDString:displayID];
  NSUInteger nativePanelWidth = [nativePanelResolution[@"width"] unsignedIntegerValue];
  NSUInteger nativePanelHeight = [nativePanelResolution[@"height"] unsignedIntegerValue];
  BOOL hasPayload = NO;

  if ((flexibleScalingEnabled || hasPanelResolutionOverride) && nativePanelWidth > 0 && nativePanelHeight > 0) {
    MDBAppendOneKeyHiDpiScaleResolutionFamily(scaleResolutions,
                                              seenScaleResolutions,
                                              nativePanelWidth,
                                              nativePanelHeight);
  }

  if (scaleResolutions.count > 0) {
    manifest[@"scale-resolutions"] = scaleResolutions;
    hasPayload = YES;
  }

  if (includeEdid && edidOverridePath.length > 0) {
    NSData *edidOverrideData = [NSData dataWithContentsOfFile:edidOverridePath];

    if (edidOverrideData.length > 0) {
      manifest[@"IODisplayEDID"] = edidOverrideData;
      hasPayload = YES;
    } else {
      NSLog(@"[macDisplayBar] Display override EDID payload unavailable: displayID=%@ path=%@",
            displayID,
            edidOverridePath);
    }
  }

  NSLog(@"[macDisplayBar] Display override bundle prepared: displayID=%@ customResolutionCount=%lu scaleResolutionCount=%lu edidOverride=%@ flexibleScaling=%@ nativePanel=%lux%lu nativePanelOverride=%@",
        displayID,
        (unsigned long)customResolutions.count,
        (unsigned long)scaleResolutions.count,
        manifest[@"IODisplayEDID"] != nil ? @"YES" : @"NO",
        flexibleScalingEnabled ? @"YES" : @"NO",
        (unsigned long)nativePanelWidth,
        (unsigned long)nativePanelHeight,
        hasPanelResolutionOverride ? @"YES" : @"NO");

  if (!hasPayload) {
    NSLog(@"[macDisplayBar] Display override bundle skipped: displayID=%@ reason=no payload", displayID);
    return @"";
  }

  NSError *serializationError = nil;
  NSData *plistData = [NSPropertyListSerialization dataWithPropertyList:manifest
                                                                  format:NSPropertyListXMLFormat_v1_0
                                                                 options:0
                                                                   error:&serializationError];

  if (plistData.length == 0 || serializationError != nil) {
    return @"";
  }

  BOOL didWrite = [plistData writeToURL:fileURL atomically:YES];
  return didWrite ? fileURL.path : @"";
}

- (BOOL)installOverrideBundleAtPath:(NSString *)bundlePath errorMessage:(NSString **)errorMessage
{
  return [self installOverrideBundleAtPath:bundlePath
                           displayIDString:@""
                                 didMutate:nil
                              errorMessage:errorMessage];
}


- (BOOL)installOverrideBundleAtPath:(NSString *)bundlePath
                    displayIDString:(NSString *)displayID
                          didMutate:(BOOL *)didMutate
                       errorMessage:(NSString **)errorMessage
{
  if (didMutate != nil) {
    *didMutate = NO;
  }

  NSURL *sourceURL = [NSURL fileURLWithPath:bundlePath];
  NSString *vendorDirectoryName = sourceURL.URLByDeletingLastPathComponent.lastPathComponent;
  NSString *productFileName = sourceURL.lastPathComponent;

  if (vendorDirectoryName.length == 0 || productFileName.length == 0) {
    if (errorMessage != nil) {
      *errorMessage = @"Display override bundle path invalid";
    }
    return NO;
  }

  NSURL *targetDirectoryURL =
      [[NSURL fileURLWithPath:RCTDisplayOverrideInstallDirectory isDirectory:YES]
          URLByAppendingPathComponent:vendorDirectoryName
                          isDirectory:YES];
  NSURL *targetFileURL = [targetDirectoryURL URLByAppendingPathComponent:productFileName];
  NSFileManager *fileManager = [NSFileManager defaultManager];
  NSError *directError = nil;
  BOOL targetExists = [fileManager fileExistsAtPath:targetFileURL.path];
  BOOL sourceMatchesTarget = targetExists && [fileManager contentsEqualAtPath:sourceURL.path andPath:targetFileURL.path];
  NSString *storedInstalledHash = displayID.length > 0 ? (self.overrideInstalledHashes[displayID] ?: @"") : @"";
  NSString *storedInstalledPath = displayID.length > 0 ? (self.overrideInstalledPaths[displayID] ?: @"") : @"";
  NSString *currentTargetHash = targetExists ? MDBSHA256FileHash(targetFileURL.path) : @"";
  BOOL targetMatchesStoredInstall = storedInstalledHash.length > 0 && [currentTargetHash isEqualToString:storedInstalledHash];
  BOOL storedTargetExists = storedInstalledPath.length > 0;
  NSString *stagedBackupPath = @"";
  NSString *stagedBackupHash = @"";

  NSLog(@"[macDisplayBar] Display override install start: source=%@ target=%@",
        sourceURL.path,
        targetFileURL.path);

  if (storedTargetExists && ![storedInstalledPath isEqualToString:targetFileURL.path]) {
    NSLog(@"[macDisplayBar] Display override install refused: display target identity changed displayID=%@ storedTarget=%@ currentTarget=%@",
          displayID,
          storedInstalledPath,
          targetFileURL.path);

    if (errorMessage != nil) {
      *errorMessage = @"Display override target identity changed";
    }

    return NO;
  }

  if (targetExists && storedInstalledHash.length > 0 && !targetMatchesStoredInstall) {
    NSLog(@"[macDisplayBar] Display override install refused: target changed externally displayID=%@ target=%@ storedHash=%@ currentHash=%@",
          displayID,
          targetFileURL.path,
          storedInstalledHash,
          currentTargetHash);

    if (errorMessage != nil) {
      *errorMessage = @"Installed override changed externally";
    }

    return NO;
  }

  if (sourceMatchesTarget) {
    if (targetExists && displayID.length > 0 && storedInstalledHash.length > 0) {
      self.overrideInstalledPaths[displayID] = targetFileURL.path;
      self.overrideInstalledHashes[displayID] = currentTargetHash;
      [self.overrideLastErrors removeObjectForKey:displayID];
      NSLog(@"[macDisplayBar] Display override install adopted matching managed target: displayID=%@ target=%@",
            displayID,
            targetFileURL.path);
    } else if (targetExists && displayID.length > 0 && storedInstalledHash.length == 0) {
      [self.overrideLastErrors removeObjectForKey:displayID];
      NSLog(@"[macDisplayBar] Display override install found externally matching target: displayID=%@ target=%@ hash=%@",
            displayID,
            targetFileURL.path,
            currentTargetHash);
    }

    NSLog(@"[macDisplayBar] Display override install skipped: target already matches source=%@",
          targetFileURL.path);
    return YES;
  }

  if (targetExists && self.overrideBackupPaths[displayID].length > 0 && storedInstalledHash.length == 0) {
    NSLog(@"[macDisplayBar] Display override install refused: managed hash missing displayID=%@ target=%@",
          displayID,
          targetFileURL.path);

    if (errorMessage != nil) {
      *errorMessage = @"Installed override ownership hash missing";
    }

    return NO;
  }

  BOOL needsBackup = targetExists && displayID.length > 0 && self.overrideBackupPaths[displayID].length == 0;

  if (needsBackup) {
    NSString *backupPath = [self backupPathForOverrideTargetURL:targetFileURL displayIDString:displayID];

    if (backupPath.length == 0 || ![fileManager copyItemAtPath:targetFileURL.path toPath:backupPath error:&directError]) {
      NSLog(@"[macDisplayBar] Display override backup failed: target=%@ backup=%@ error=%@",
            targetFileURL.path,
            backupPath,
            directError.localizedDescription ?: @"");

      if (errorMessage != nil) {
        *errorMessage = directError.localizedDescription ?: @"Display override backup failed";
      }

      return NO;
    }

    stagedBackupPath = backupPath;
    stagedBackupHash = MDBSHA256FileHash(backupPath);
    NSLog(@"[macDisplayBar] Display override backup created: displayID=%@ target=%@ backup=%@",
          displayID,
          targetFileURL.path,
          backupPath);
  }

  [fileManager createDirectoryAtURL:targetDirectoryURL
        withIntermediateDirectories:YES
                         attributes:nil
                              error:&directError];

  if (directError == nil) {
    NSURL *directTempURL = [targetDirectoryURL URLByAppendingPathComponent:[NSString stringWithFormat:@".%@.%@.tmp",
                                                                                                      productFileName,
                                                                                                      [[NSUUID UUID] UUIDString]]];

    [fileManager removeItemAtURL:directTempURL error:nil];

    if ([fileManager copyItemAtURL:sourceURL toURL:directTempURL error:&directError] &&
        [fileManager replaceItemAtURL:targetFileURL
                         withItemAtURL:directTempURL
                        backupItemName:nil
                               options:0
                      resultingItemURL:nil
                                 error:&directError]) {
      NSLog(@"[macDisplayBar] Display override direct install verified: target=%@",
            targetFileURL.path);
      if (stagedBackupPath.length > 0) {
        self.overrideBackupPaths[displayID] = stagedBackupPath;
        self.overrideBackupHashes[displayID] = stagedBackupHash;
      }
      if (didMutate != nil) {
        *didMutate = YES;
      }
      return YES;
    }

    [fileManager removeItemAtURL:directTempURL error:nil];
  }

  NSLog(@"[macDisplayBar] Display override direct install failed: target=%@ error=%@",
        targetFileURL.path,
        directError.localizedDescription ?: @"");

  NSURL *stagedDirectoryURL = [[NSURL fileURLWithPath:NSTemporaryDirectory() isDirectory:YES]
      URLByAppendingPathComponent:[NSString stringWithFormat:@"macDisplayBar-overrides/%@", [[NSUUID UUID] UUIDString]]
                      isDirectory:YES];
  NSURL *stagedSourceURL = [stagedDirectoryURL URLByAppendingPathComponent:productFileName];
  NSError *stagingError = nil;

  [fileManager createDirectoryAtURL:stagedDirectoryURL
        withIntermediateDirectories:YES
                         attributes:nil
                              error:&stagingError];

  if (stagingError == nil) {
    [fileManager copyItemAtURL:sourceURL toURL:stagedSourceURL error:&stagingError];
  }

  if (stagingError != nil) {
    NSLog(@"[macDisplayBar] Display override privileged install staging failed: source=%@ error=%@",
          sourceURL.path,
          stagingError.localizedDescription ?: @"");

    if (errorMessage != nil) {
      *errorMessage = stagingError.localizedDescription ?: @"Display override staging failed";
    }

    [fileManager removeItemAtURL:stagedDirectoryURL error:nil];
    return NO;
  }

  NSLog(@"[macDisplayBar] Display override privileged install staged source: source=%@ stagedSource=%@",
        sourceURL.path,
        stagedSourceURL.path);

  NSString *targetTempPath = [targetFileURL.path stringByAppendingFormat:@".%@.tmp", [[NSUUID UUID] UUIDString]];
  NSString *expectedStagedSourceHash = MDBSHA256FileHash(stagedSourceURL.path);
  NSString *stagedSourceHashCommand = MDBShellSHA256SizeCommand(stagedSourceURL.path);
  NSString *stagedSourcePrecondition = [NSString stringWithFormat:@"if /bin/test ! -f %@ || /bin/test \"%@\" != %@; then exit 75; fi",
                                                                  MDBShellQuotedString(stagedSourceURL.path),
                                                                  expectedStagedSourceHash,
                                                                  stagedSourceHashCommand];
  NSString *expectedTargetHash = targetExists ? currentTargetHash : @"";
  NSString *targetHashCommand = MDBShellSHA256SizeCommand(targetFileURL.path);
  NSString *targetPrecondition = targetExists
      ? [NSString stringWithFormat:@"if /bin/test ! -f %@ || /bin/test \"%@\" != %@; then exit 73; fi",
                                   MDBShellQuotedString(targetFileURL.path),
                                   expectedTargetHash,
                                   targetHashCommand]
      : [NSString stringWithFormat:@"if /bin/test -e %@; then exit 74; fi",
                                   MDBShellQuotedString(targetFileURL.path)];
  NSString *command = [NSString stringWithFormat:@"/bin/mkdir -p %@ && %@ && %@ && /usr/bin/install -o root -g wheel -m 0644 %@ %@ && /bin/mv -f %@ %@",
                                                 MDBShellQuotedString(targetDirectoryURL.path),
                                                 targetPrecondition,
                                                 stagedSourcePrecondition,
                                                 MDBShellQuotedString(stagedSourceURL.path),
                                                 MDBShellQuotedString(targetTempPath),
                                                 MDBShellQuotedString(targetTempPath),
                                                 MDBShellQuotedString(targetFileURL.path)];
  NSString *script = [NSString stringWithFormat:@"do shell script \"%@\" with administrator privileges",
                                                MDBAppleScriptQuotedString(command)];
  NSTask *task = [NSTask new];
  NSPipe *errorPipe = [NSPipe pipe];

  task.launchPath = @"/usr/bin/osascript";
  task.arguments = @[ @"-e", script ];
  task.standardError = errorPipe;

  @try {
    [[NSNotificationCenter defaultCenter] postNotificationName:RCTDisplayPrivilegedInstallWillBeginNotification
                                                        object:self];
    [task launch];
    [task waitUntilExit];
  } @catch (NSException *exception) {
    NSLog(@"[macDisplayBar] Display override privileged install exception: target=%@ reason=%@",
          targetFileURL.path,
          exception.reason ?: @"");
    if (errorMessage != nil) {
      *errorMessage = exception.reason ?: @"Privileged override install failed";
    }
    [[NSNotificationCenter defaultCenter] postNotificationName:RCTDisplayPrivilegedInstallDidEndNotification
                                                        object:self];
    [fileManager removeItemAtURL:stagedDirectoryURL error:nil];
    return NO;
  }

  [[NSNotificationCenter defaultCenter] postNotificationName:RCTDisplayPrivilegedInstallDidEndNotification
                                                      object:self];

  if (task.terminationStatus == 0) {
    BOOL targetMatches = [fileManager contentsEqualAtPath:stagedSourceURL.path andPath:targetFileURL.path];

    if (!targetMatches) {
      NSLog(@"[macDisplayBar] Display override privileged install verification failed: target=%@",
            targetFileURL.path);

      if (errorMessage != nil) {
        *errorMessage = @"installed override contents do not match source";
      }

      [fileManager removeItemAtURL:stagedDirectoryURL error:nil];
      return NO;
    }

    NSLog(@"[macDisplayBar] Display override privileged install verified: target=%@",
          targetFileURL.path);
    if (stagedBackupPath.length > 0) {
      self.overrideBackupPaths[displayID] = stagedBackupPath;
      self.overrideBackupHashes[displayID] = stagedBackupHash;
    }
    if (didMutate != nil) {
      *didMutate = YES;
    }
    [fileManager removeItemAtURL:stagedDirectoryURL error:nil];
    return YES;
  }

  NSData *errorData = [errorPipe.fileHandleForReading readDataToEndOfFile];
  NSString *privilegedError =
      [[NSString alloc] initWithData:errorData encoding:NSUTF8StringEncoding];
  NSString *fallbackError = directError.localizedDescription ?: @"Privileged override install failed";

  NSLog(@"[macDisplayBar] Display override privileged install failed: status=%d target=%@ stderr=%@ directError=%@",
        task.terminationStatus,
        targetFileURL.path,
        privilegedError ?: @"",
        directError.localizedDescription ?: @"");

  if (errorMessage != nil) {
    *errorMessage = privilegedError.length > 0 ? privilegedError : fallbackError;
  }

  [fileManager removeItemAtURL:stagedDirectoryURL error:nil];
  return NO;
}


- (BOOL)removeInstalledOverrideForDisplayIDString:(NSString *)displayID errorMessage:(NSString **)errorMessage
{
  NSURL *targetFileURL = [self overrideTargetFileURLForLifecycleKey:displayID];
  NSString *installedPath = self.overrideInstalledPaths[displayID] ?: @"";
  NSString *bundlePath = self.overrideBundlePaths[displayID] ?: @"";
  NSString *backupPath = self.overrideBackupPaths[displayID] ?: @"";
  NSString *installedHash = self.overrideInstalledHashes[displayID] ?: @"";
  NSString *backupHash = self.overrideBackupHashes[displayID] ?: @"";
  NSFileManager *fileManager = [NSFileManager defaultManager];
  BOOL targetExists = targetFileURL.path.length > 0 && [fileManager fileExistsAtPath:targetFileURL.path];

  if (targetFileURL.path.length == 0) {
    if (errorMessage != nil) {
      *errorMessage = @"Display override target path invalid";
    }
    return NO;
  }

  if (targetExists && installedHash.length == 0 && backupPath.length == 0) {
    if (errorMessage != nil) {
      *errorMessage = @"Installed override is not managed by macDisplayBar";
    }
    NSLog(@"[macDisplayBar] Display override remove refused: unmanaged target displayID=%@ target=%@ installedPath=%@ bundlePath=%@",
          displayID,
          targetFileURL.path,
          installedPath,
          bundlePath);
    return NO;
  }

  if (installedPath.length > 0 && ![installedPath isEqualToString:targetFileURL.path]) {
    if (errorMessage != nil) {
      *errorMessage = @"Display override target identity changed";
    }
    NSLog(@"[macDisplayBar] Display override remove refused: displayID=%@ storedTarget=%@ currentTarget=%@",
          displayID,
          installedPath,
          targetFileURL.path);
    return NO;
  }

  if (!targetExists && backupPath.length == 0) {
    return YES;
  }

  BOOL targetMatchesInstalledHash = targetExists && MDBFileMatchesStoredHash(targetFileURL.path, installedHash);

  if (targetExists && !targetMatchesInstalledHash) {
    if (errorMessage != nil) {
      *errorMessage = @"Installed override is not managed by macDisplayBar";
    }
    NSLog(@"[macDisplayBar] Display override remove refused: displayID=%@ target=%@ installedPath=%@ bundlePath=%@ installedHash=%@ currentHash=%@",
          displayID,
          targetFileURL.path,
          installedPath,
          bundlePath,
          installedHash,
          MDBSHA256FileHash(targetFileURL.path));
    return NO;
  }

  if (backupPath.length > 0 && !MDBFileMatchesStoredHash(backupPath, backupHash)) {
    if (errorMessage != nil) {
      *errorMessage = @"Display override backup changed externally";
    }
    NSLog(@"[macDisplayBar] Display override backup restore refused: displayID=%@ backup=%@ backupHash=%@ currentHash=%@",
          displayID,
          backupPath,
          backupHash,
          MDBSHA256FileHash(backupPath));
    return NO;
  }

  NSError *directError = nil;

  if (backupPath.length > 0 && [fileManager fileExistsAtPath:backupPath]) {
    NSURL *directTempURL = [targetFileURL.URLByDeletingLastPathComponent URLByAppendingPathComponent:[NSString stringWithFormat:@".%@.%@.tmp",
                                                                                                                                targetFileURL.lastPathComponent,
                                                                                                                                [[NSUUID UUID] UUIDString]]];

    [fileManager removeItemAtURL:directTempURL error:nil];

    if ([fileManager copyItemAtPath:backupPath toPath:directTempURL.path error:&directError] &&
        [fileManager replaceItemAtURL:targetFileURL
                         withItemAtURL:directTempURL
                        backupItemName:nil
                               options:0
                      resultingItemURL:nil
                                 error:&directError]) {
      NSLog(@"[macDisplayBar] Display override backup restored: displayID=%@ target=%@ backup=%@",
            displayID,
            targetFileURL.path,
            backupPath);
      return YES;
    }

    [fileManager removeItemAtURL:directTempURL error:nil];
  } else if ([fileManager removeItemAtURL:targetFileURL error:&directError]) {
    NSLog(@"[macDisplayBar] Display override removed: displayID=%@ target=%@",
          displayID,
          targetFileURL.path);
    return YES;
  }

  NSString *command = nil;

  if (backupPath.length > 0 && [fileManager fileExistsAtPath:backupPath]) {
    NSString *targetTempPath = [targetFileURL.path stringByAppendingFormat:@".%@.tmp", [[NSUUID UUID] UUIDString]];
    NSString *expectedTargetHash = targetExists ? installedHash : @"";
    NSString *targetHashCommand = MDBShellSHA256SizeCommand(targetFileURL.path);
    NSString *expectedBackupHash = backupHash;
    NSString *backupHashCommand = MDBShellSHA256SizeCommand(backupPath);
    NSString *backupPrecondition = [NSString stringWithFormat:@"if /bin/test ! -f %@ || /bin/test \"%@\" != %@; then exit 75; fi",
                                                              MDBShellQuotedString(backupPath),
                                                              expectedBackupHash,
                                                              backupHashCommand];
    NSString *targetPrecondition = targetExists
        ? [NSString stringWithFormat:@"if /bin/test ! -f %@ || /bin/test \"%@\" != %@; then exit 73; fi",
                                     MDBShellQuotedString(targetFileURL.path),
                                     expectedTargetHash,
                                     targetHashCommand]
        : [NSString stringWithFormat:@"if /bin/test -e %@; then exit 74; fi",
                                     MDBShellQuotedString(targetFileURL.path)];
    command = [NSString stringWithFormat:@"%@ && %@ && /usr/bin/install -o root -g wheel -m 0644 %@ %@ && /bin/mv -f %@ %@",
                                         targetPrecondition,
                                         backupPrecondition,
                                         MDBShellQuotedString(backupPath),
                                         MDBShellQuotedString(targetTempPath),
                                         MDBShellQuotedString(targetTempPath),
                                         MDBShellQuotedString(targetFileURL.path)];
  } else {
    NSString *expectedTargetHash = installedHash;
    command = [NSString stringWithFormat:@"if /bin/test ! -f %@ || /bin/test \"%@\" != %@; then exit 73; fi && /bin/rm -f %@",
                                         MDBShellQuotedString(targetFileURL.path),
                                         expectedTargetHash,
                                         MDBShellSHA256SizeCommand(targetFileURL.path),
                                         MDBShellQuotedString(targetFileURL.path)];
  }

  NSString *script = [NSString stringWithFormat:@"do shell script \"%@\" with administrator privileges",
                                                MDBAppleScriptQuotedString(command)];
  NSTask *task = [NSTask new];
  NSPipe *errorPipe = [NSPipe pipe];

  task.launchPath = @"/usr/bin/osascript";
  task.arguments = @[ @"-e", script ];
  task.standardError = errorPipe;

  @try {
    [[NSNotificationCenter defaultCenter] postNotificationName:RCTDisplayPrivilegedInstallWillBeginNotification
                                                        object:self];
    [task launch];
    [task waitUntilExit];
  } @catch (NSException *exception) {
    if (errorMessage != nil) {
      *errorMessage = exception.reason ?: @"Privileged override remove failed";
    }
    [[NSNotificationCenter defaultCenter] postNotificationName:RCTDisplayPrivilegedInstallDidEndNotification
                                                        object:self];
    return NO;
  }

  [[NSNotificationCenter defaultCenter] postNotificationName:RCTDisplayPrivilegedInstallDidEndNotification
                                                      object:self];

  if (task.terminationStatus == 0) {
    BOOL didApply = NO;

    if (backupPath.length > 0 && [fileManager fileExistsAtPath:backupPath]) {
      didApply = [fileManager contentsEqualAtPath:backupPath andPath:targetFileURL.path];
    } else {
      didApply = ![fileManager fileExistsAtPath:targetFileURL.path];
    }

    if (didApply) {
      NSLog(@"[macDisplayBar] Display override privileged remove verified: displayID=%@ target=%@",
            displayID,
            targetFileURL.path);
      return YES;
    }
  }

  NSData *errorData = [errorPipe.fileHandleForReading readDataToEndOfFile];
  NSString *privilegedError =
      [[NSString alloc] initWithData:errorData encoding:NSUTF8StringEncoding];

  NSLog(@"[macDisplayBar] Display override privileged remove failed: status=%d target=%@ stderr=%@ directError=%@",
        task.terminationStatus,
        targetFileURL.path,
        privilegedError ?: @"",
        directError.localizedDescription ?: @"");

  if (errorMessage != nil) {
    *errorMessage = privilegedError.length > 0 ? privilegedError : (directError.localizedDescription ?: @"Privileged override remove failed");
  }

  return NO;
}


- (BOOL)requestDisplayReinitializeForDisplayID:(CGDirectDisplayID)displayID errorMessage:(NSString **)errorMessage
{
  uint32_t vendorID = CGDisplayVendorNumber(displayID);
  uint32_t productID = CGDisplayModelNumber(displayID);
  uint32_t serialNumber = CGDisplaySerialNumber(displayID);
  io_iterator_t iterator = MACH_PORT_NULL;
  kern_return_t result = IOServiceGetMatchingServices(kIOMainPortDefault, IOServiceMatching("IODisplayConnect"), &iterator);

  if (result != KERN_SUCCESS || iterator == MACH_PORT_NULL) {
    if (errorMessage != nil) {
      *errorMessage = [NSString stringWithFormat:@"IODisplayConnect lookup failed: 0x%08x", result];
    }
    return NO;
  }

  io_service_t service = MACH_PORT_NULL;

  while ((service = IOIteratorNext(iterator)) != MACH_PORT_NULL) {
    NSDictionary *info = CFBridgingRelease(IODisplayCreateInfoDictionary(service, kIODisplayOnlyPreferredName));
    NSNumber *candidateVendorID = info[[NSString stringWithUTF8String:kDisplayVendorID]];
    NSNumber *candidateProductID = info[[NSString stringWithUTF8String:kDisplayProductID]];
    NSNumber *candidateSerialNumber = info[[NSString stringWithUTF8String:kDisplaySerialNumber]];
    BOOL vendorMatches = candidateVendorID.unsignedIntValue == vendorID;
    BOOL productMatches = candidateProductID.unsignedIntValue == productID;
    BOOL serialMatches = serialNumber == 0 || candidateSerialNumber.unsignedIntValue == serialNumber;

    if (vendorMatches && productMatches && serialMatches) {
      kern_return_t probeResult = IOServiceRequestProbe(service, kIOFBUserRequestProbe);
      IOObjectRelease(service);
      IOObjectRelease(iterator);

      if (probeResult == KERN_SUCCESS) {
        NSLog(@"[macDisplayBar] Display override reinitialize requested: displayID=%u", displayID);
        return YES;
      }

      if (errorMessage != nil) {
        *errorMessage = [NSString stringWithFormat:@"Display reinitialize failed: 0x%08x", probeResult];
      }
      return NO;
    }

    IOObjectRelease(service);
  }

  IOObjectRelease(iterator);

  if (errorMessage != nil) {
    *errorMessage = @"Matching IODisplayConnect service not found";
  }
  return NO;
}

- (NSString *)customResolutionStorageKeyForDisplayIDString:(NSString *)displayID
{
  NSString *lifecycleKey = [self overrideLifecycleKeyForDisplayIDString:displayID];
  return lifecycleKey.length > 0 ? lifecycleKey : displayID;
}


- (NSArray<NSDictionary *> *)customResolutionRequestsForDisplayIDString:(NSString *)displayID
{
  NSString *lifecycleKey = [self overrideLifecycleKeyForDisplayIDString:displayID];
  NSArray<NSDictionary *> *lifecycleRequests = self.customResolutionRequests[lifecycleKey];

  if (lifecycleRequests.count > 0) {
    return lifecycleRequests;
  }

  return self.customResolutionRequests[displayID] ?: @[];
}


- (NSDictionary *)advancedStateForDisplayID:(CGDirectDisplayID)displayID displayIDString:(NSString *)displayIDString
{
  NSData *edidData = [self edidDataForDisplayID:displayID];
  NSArray *customResolutions = [self customResolutionRequestsForDisplayIDString:displayIDString];
  NSNumber *rotationRequest = self.rotationRequests[displayIDString] ?: @(CGDisplayRotation(displayID));
  NSDictionary *detectedPanelResolution = [self detectedNativePanelResolutionForDisplayID:displayID];
  NSDictionary *panelResolution = [self nativePanelResolutionForDisplayID:displayID displayIDString:displayIDString];
  NSString *lifecycleKey = [self overrideLifecycleKeyForDisplayIDString:displayIDString];
  NSDictionary *panelOverride = self.nativePanelResolutionOverrides[lifecycleKey] ?:
      self.nativePanelResolutionOverrides[displayIDString] ?: @{};
  BOOL hasPanelOverride = [self nativePanelResolutionOverrideExistsForDisplayIDString:displayIDString];
  BOOL flexibleScalingEnabled = [self flexibleScalingEnabledForDisplayIDString:displayIDString];
  NSUInteger detectedPanelWidth = [detectedPanelResolution[@"width"] unsignedIntegerValue];
  NSUInteger detectedPanelHeight = [detectedPanelResolution[@"height"] unsignedIntegerValue];
  NSUInteger panelWidth = [panelResolution[@"width"] unsignedIntegerValue];
  NSUInteger panelHeight = [panelResolution[@"height"] unsignedIntegerValue];
  NSUInteger overridePanelWidth = hasPanelOverride ? [panelOverride[@"width"] unsignedIntegerValue] : 0;
  NSUInteger overridePanelHeight = hasPanelOverride ? [panelOverride[@"height"] unsignedIntegerValue] : 0;
  BOOL overrideInstalled = self.overrideInstalledPaths[lifecycleKey].length > 0;
  BOOL overridePendingReboot = [self.overridePendingReboot[lifecycleKey] boolValue];
  BOOL overridePendingReinitialize = [self.overridePendingReinitialize[lifecycleKey] boolValue];
  NSString *nativePanelResolutionStatus = hasPanelOverride
      ? [NSString stringWithFormat:@"Override %lux%lu (detected %lux%lu)",
                                   (unsigned long)overridePanelWidth,
                                   (unsigned long)overridePanelHeight,
                                   (unsigned long)detectedPanelWidth,
                                   (unsigned long)detectedPanelHeight]
      : [NSString stringWithFormat:@"Detected %lux%lu",
                                   (unsigned long)detectedPanelWidth,
                                   (unsigned long)detectedPanelHeight];

  if (hasPanelOverride) {
    if (!overrideInstalled) {
      nativePanelResolutionStatus =
          [nativePanelResolutionStatus stringByAppendingString:@" - install required"];
    } else if (overridePendingReboot) {
      nativePanelResolutionStatus =
          [nativePanelResolutionStatus stringByAppendingString:@" - PC Restart required"];
    } else if (overridePendingReinitialize) {
      nativePanelResolutionStatus =
          [nativePanelResolutionStatus stringByAppendingString:@" - reload required"];
    }
  }

  NSString *flexibleScalingStatus = @"Disabled";

  if (flexibleScalingEnabled) {
    if (!overrideInstalled) {
      flexibleScalingStatus = @"Enabled - install required";
    } else if (overridePendingReboot) {
      flexibleScalingStatus = @"Enabled - PC Restart required";
    } else if (overridePendingReinitialize) {
      flexibleScalingStatus = @"Enabled - reload required";
    } else {
      flexibleScalingStatus = @"Enabled";
    }
  }

  return @{
    @"supportsEdidExport" : @(edidData.length > 0),
    @"edidBytes" : @(edidData.length),
    @"edidExportPath" : self.edidExportPaths[displayIDString] ?: @"",
    @"edidOverridePath" : self.edidOverridePaths[displayIDString] ?: @"",
    @"edidOverrideStatus" : self.edidOverrideStatus[displayIDString] ?: @"No override",
    @"overrideBundlePath" : self.overrideBundlePaths[displayIDString] ?: @"",
    @"overrideBundleStatus" : self.overrideBundleStatus[displayIDString] ?: @"No bundle",
    @"overrideInstalledPath" : self.overrideInstalledPaths[lifecycleKey] ?: @"",
    @"overrideBackupPath" : self.overrideBackupPaths[lifecycleKey] ?: @"",
    @"overrideInstalledHash" : self.overrideInstalledHashes[lifecycleKey] ?: @"",
    @"overrideBackupHash" : self.overrideBackupHashes[lifecycleKey] ?: @"",
    @"overridePendingReboot" : @(overridePendingReboot),
    @"overridePendingReinitialize" : @(overridePendingReinitialize),
    @"overrideLastError" : self.overrideLastErrors[lifecycleKey] ?: @"",
    @"nativePanelWidth" : @(panelWidth),
    @"nativePanelHeight" : @(panelHeight),
    @"nativePanelOverrideWidth" : @(overridePanelWidth),
    @"nativePanelOverrideHeight" : @(overridePanelHeight),
    @"nativePanelResolutionStatus" : nativePanelResolutionStatus,
    @"flexibleScalingEnabled" : @(flexibleScalingEnabled),
    @"flexibleScalingStatus" : flexibleScalingStatus,
    @"rotationRequest" : rotationRequest,
    @"rotationStatus" : self.rotationStatus[displayIDString] ?: @"Current",
    @"softConnectionState" : self.softConnectionStates[displayIDString] ?: @"connected",
    @"xdrUpscaleState" : self.xdrUpscaleStates[displayIDString] ?: @"disabled",
    @"lastOperation" : self.advancedOperations[displayIDString] ?: @"",
    @"lastOperationAt" : self.advancedOperationDates[displayIDString] ?: @"",
    @"customResolutions" : customResolutions,
  };
}


- (BOOL)overridePayloadExistsForDisplayIDString:(NSString *)displayID
{
  NSArray *customResolutions = [self customResolutionRequestsForDisplayIDString:displayID];
  NSString *edidOverridePath = self.edidOverridePaths[displayID] ?: @"";
  return customResolutions.count > 0 || edidOverridePath.length > 0 ||
      [self flexibleScalingEnabledForDisplayIDString:displayID] ||
      [self nativePanelResolutionOverrideExistsForDisplayIDString:displayID];
}


- (NSURL *)overrideTargetFileURLForDisplayIDString:(NSString *)displayID
{
  if ([displayID hasPrefix:@"/"]) {
    NSLog(@"[macDisplayBar] Display override target rejected: displayID=%@ reason=absolute displayID not allowed",
          displayID);
    return nil;
  }

  CGDirectDisplayID directDisplayID = (CGDirectDisplayID)displayID.integerValue;
  uint32_t vendorID = CGDisplayVendorNumber(directDisplayID);
  uint32_t productID = CGDisplayModelNumber(directDisplayID);

  if (vendorID == 0 && productID == 0) {
    return nil;
  }

  NSString *vendorDirectoryName = [NSString stringWithFormat:@"DisplayVendorID-%x", vendorID];
  NSString *productFileName = [NSString stringWithFormat:@"DisplayProductID-%x", productID];
  return [[[NSURL fileURLWithPath:RCTDisplayOverrideInstallDirectory isDirectory:YES]
      URLByAppendingPathComponent:vendorDirectoryName
		                      isDirectory:YES] URLByAppendingPathComponent:productFileName];
}


- (NSURL *)overrideTargetFileURLForLifecycleKey:(NSString *)lifecycleKey
{
  if (![lifecycleKey hasPrefix:@"/"]) {
    return [self overrideTargetFileURLForDisplayIDString:lifecycleKey];
  }

  NSString *overrideDirectory = [RCTDisplayOverrideInstallDirectory stringByStandardizingPath];
  NSString *targetPath = [lifecycleKey stringByStandardizingPath];
  NSString *requiredPrefix = [overrideDirectory hasSuffix:@"/"]
      ? overrideDirectory
      : [overrideDirectory stringByAppendingString:@"/"];

  if (![targetPath hasPrefix:requiredPrefix]) {
    NSLog(@"[macDisplayBar] Display override lifecycle target rejected: target=%@ reason=outside display override directory",
          targetPath);
    return nil;
  }

  return [NSURL fileURLWithPath:targetPath];
}


- (NSString *)overrideLifecycleKeyForDisplayIDString:(NSString *)displayID
{
  NSURL *targetURL = [self overrideTargetFileURLForDisplayIDString:displayID];
  return targetURL.path.length > 0 ? targetURL.path : displayID;
}


- (NSString *)backupPathForOverrideTargetURL:(NSURL *)targetURL displayIDString:(NSString *)displayID
{
  NSString *safeDisplayID = MDBSafeFileNameComponent(displayID, @"display");
  NSString *backupFileName =
      [NSString stringWithFormat:@"%@-%@-%@.backup",
                                 targetURL.lastPathComponent ?: @"DisplayProductID",
                                 safeDisplayID,
                                 [[NSUUID UUID] UUIDString]];
  NSURL *baseDirectoryURL =
      [[[NSFileManager defaultManager] URLsForDirectory:NSDocumentDirectory inDomains:NSUserDomainMask].firstObject
          URLByAppendingPathComponent:@"MacDisplayBar/Overrides/Backups"
                          isDirectory:YES];
  NSURL *backupURL = [baseDirectoryURL URLByAppendingPathComponent:backupFileName];
  NSError *directoryError = nil;

  [[NSFileManager defaultManager] createDirectoryAtURL:baseDirectoryURL
                           withIntermediateDirectories:YES
                                            attributes:nil
                                                 error:&directoryError];

  return directoryError == nil ? backupURL.path : @"";
}


- (void)clearRebootPendingStatesAfterSystemBoot
{
  NSTimeInterval bootTime = MDBSystemBootTime();

  if (bootTime <= 0) {
    return;
  }

  for (NSString *displayID in self.overrideInstallTimes.allKeys) {
    NSNumber *installTime = self.overrideInstallTimes[displayID];

    if (installTime.doubleValue > 0 && installTime.doubleValue < bootTime) {
      [self.overridePendingReboot removeObjectForKey:displayID];
      [self.overridePendingReinitialize removeObjectForKey:displayID];
    }
  }
}


